#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int avg = (A[i] + A[j]) / 2;
                int *ptr = bsearch(&avg, A, N, sizeof(int), compare);
                if (ptr != NULL) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

