const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    A.sort((a, b) => a - b);
    let count = 0;
    for (let j = 0; j < N; j++) {
        for (let k = j + 1; k < N; k++) {
            const avg = Math.floor((A[j] + A[k]) / 2);
            if (A.includes(avg)) {
                count++;
            }
        }
    }
    console.log(count);
}

